// ============================================================
// HMAC-SHA256 Signature Verification
// ============================================================
// Ensures the webhook request actually came from GoWater
// and wasn't spoofed by a third party.
//
// GoWater sends: X-Webhook-Signature: sha256=<hex>
// We recompute the HMAC using our shared secret and compare.
// ============================================================

const crypto = require('crypto');

const SHARED_SECRET = $env.GOWATER_WEBHOOK_SECRET || '';

const signature = $input.first().json.headers['x-webhook-signature'] || '';
const body = JSON.stringify($input.first().json.body);

if (!SHARED_SECRET) {
  // No secret configured — skip verification (dev mode)
  return [{ json: { ...($input.first().json.body), _verified: false } }];
}

const expected = 'sha256=' + crypto
  .createHmac('sha256', SHARED_SECRET)
  .update(body)
  .digest('hex');

if (signature !== expected) {
  throw new Error('Invalid webhook signature — request rejected');
}

return [{ json: { ...($input.first().json.body), _verified: true } }];

// ============================================================
// Late Check-In Detection (Philippines Labor Standards)
// ============================================================
// Standard shift starts at 9:00 AM PHT (UTC+8).
// If check-in is after 9:00 AM, flag as late and calculate
// how many minutes late.
// ============================================================

const item = $input.first().json;
const ts = new Date(item.timestamp);

// Convert to PHT (UTC+8) using manual offset
// (toLocaleTimeString is unreliable on server runtimes)
const phtMs = ts.getTime() + (8 * 60 * 60 * 1000);
const pht = new Date(phtMs);
const hours = pht.getUTCHours();
const minutes = pht.getUTCMinutes();

// 9:00 AM threshold
const SHIFT_START_HOUR = 9;
const SHIFT_START_MIN = 0;

const isLate = (hours > SHIFT_START_HOUR) ||
  (hours === SHIFT_START_HOUR && minutes > SHIFT_START_MIN);

let minutesLate = 0;
if (isLate) {
  minutesLate = ((hours - SHIFT_START_HOUR) * 60) + (minutes - SHIFT_START_MIN);
}

const timeStr = `${String(hours % 12 || 12).padStart(2, '0')}:${String(minutes).padStart(2, '0')} ${hours >= 12 ? 'PM' : 'AM'}`;

return [{
  json: {
    ...item,
    _phtTime: timeStr,
    _isLate: isLate,
    _minutesLate: minutesLate
  }
}];

// ============================================================
// Check-Out: Calculate overtime & format hours
// ============================================================
// Philippine labor: regular = 8 hrs, OT = anything above 8.
// OT rate: 1.25x on regular days.
// Night differential: +10% for work between 10 PM - 6 AM.
// ============================================================

const item = $input.first().json;
const totalHours = Number(item.data.totalHours) || 0;
const breakMins = Number(item.data.totalBreakDuration) || 0;

const REGULAR_HOURS = 8;
const netHours = totalHours - (breakMins / 60);
const overtime = Math.max(0, netHours - REGULAR_HOURS);
const regularHrs = Math.min(netHours, REGULAR_HOURS);
const isUndertime = netHours < REGULAR_HOURS;
const undertimeHrs = isUndertime ? (REGULAR_HOURS - netHours) : 0;

// Format check-out time to PHT
const ts = new Date(item.data.checkOutTime || item.timestamp);
const phtMs = ts.getTime() + (8 * 60 * 60 * 1000);
const pht = new Date(phtMs);
const hours = pht.getUTCHours();
const minutes = pht.getUTCMinutes();
const timeStr = `${String(hours % 12 || 12).padStart(2, '0')}:${String(minutes).padStart(2, '0')} ${hours >= 12 ? 'PM' : 'AM'}`;

return [{
  json: {
    ...item,
    _phtTime: timeStr,
    _regularHrs: regularHrs.toFixed(2),
    _overtimeHrs: overtime.toFixed(2),
    _netHours: netHours.toFixed(2),
    _isUndertime: isUndertime,
    _undertimeHrs: undertimeHrs.toFixed(2),
    _hasOvertime: overtime > 0
  }
}];

// ============================================================
// Break Compliance: Philippine DOLE Labor Standards
// ============================================================
// DOLE Rule: Employees working 6+ hours are entitled to a
// 60-minute meal break (not counted as work time).
// Breaks shorter than 20 minutes are counted as work time.
//
// This node checks:
// 1. Break too short (< 30 min) — may violate DOLE standards
// 2. Break too long  (> 120 min) — needs manager review
// ============================================================

const item = $input.first().json;
const breakSec = Number(item.data.breakDurationSeconds) || 0;
const breakMin = Math.floor(breakSec / 60);
const totalBreakMin = Math.floor((Number(item.data.totalBreakDuration) || 0) / 60);

const SHORT_BREAK_THRESHOLD = 30;  // minutes
const LONG_BREAK_THRESHOLD = 120;  // minutes

let complianceFlag = 'ok';
let complianceMsg = '';

if (breakMin < SHORT_BREAK_THRESHOLD) {
  complianceFlag = 'short_break';
  complianceMsg = `Break was only ${breakMin} min — possible DOLE compliance issue (minimum 60 min for 6+ hr shifts)`;
} else if (breakMin > LONG_BREAK_THRESHOLD) {
  complianceFlag = 'long_break';
  complianceMsg = `Extended break of ${breakMin} min — needs manager review`;
}

return [{
  json: {
    ...item,
    _breakMin: breakMin,
    _totalBreakMin: totalBreakMin,
    _complianceFlag: complianceFlag,
    _complianceMsg: complianceMsg
  }
}];

